-- ============================================================
-- 08_merchants_import.sql — import all 693 stores as vendor_profiles.
-- Additive + idempotent. psql compatible. Run AFTER run_all.sql.
--   * 630 stores with a domain (keyed on domain; linked to orders)
--   * 63 stores with NO domain in the CSV (domain left blank; keyed on name)
-- ============================================================
ALTER TABLE vendor_profiles ALTER COLUMN user_id DROP NOT NULL;
ALTER TABLE vendor_profiles ADD COLUMN IF NOT EXISTS domain text;
ALTER TABLE vendor_profiles ALTER COLUMN status SET DEFAULT 'approved';
CREATE UNIQUE INDEX IF NOT EXISTS idx_vendor_profiles_domain ON vendor_profiles(domain);

-- Stores WITH a domain — upsert on domain.
ON CONFLICT (domain) DO UPDATE SET
  legal_name=EXCLUDED.legal_name, trade_name=EXCLUDED.trade_name,
  website_url=EXCLUDED.website_url, city=EXCLUDED.city, country=EXCLUDED.country, updated_at=now();

-- Stores with NO domain — blank domain, inserted once (keyed on trade_name; skip nothing).
